// sensor_id가 없으면 로그 생략
if (!msg.payload.sensor_id) return null;

let sensor = msg.payload.sensor_id;
let topic = msg.topic;
let payloadStr = JSON.stringify(msg.payload);

// ✅ 중복 메시지 방지 (최근 메시지 캐시 비교)
let last_entry = context.get("last_entry") || "";
let current = `[${sensor}] → [${topic}] ${payloadStr}`;
if (last_entry === current) {
    return null;  // 중복이면 무시
}
context.set("last_entry", current);

// ✅ 로그 시간
let now = new Date().toLocaleTimeString();
let entry = `[${now}] [${sensor}] → [${topic}] ${payloadStr}`;

// ✅ 로그 누적
let previous = context.get("log") || "";

// 최대 10줄 유지
let lines = (current + "\n" + previous).split("\n").slice(0, 10).join("\n");

// 저장
context.set("log", lines);

// 출력
msg.payload = lines;
return msg;

// 버튼/브로커 양쪽에서 들어오는 payload를 통일
if (typeof msg.payload === "string") {
  try { msg.payload = JSON.parse(msg.payload); } catch(e) { /* noop */ }
}
const cmd = (msg.payload && msg.payload.command) || "";

// 화면 표기 매핑
let displayText = "✅ 정상 상태!";
if (cmd === "yellow_flash") {
  displayText = "🟡 경고 점멸 중";
} else if (cmd === "fire_confirmed") {
  displayText = "🔴 화재 발생!";
} else if (cmd === "reset_ui") {
  displayText = "✅ 정상 상태!";
}

// 공통 출력
msg.payload.display = displayText;
return msg;

