// 문자열/숫자/불리언 모두 대응
function toBit(x){
  if (x === 1 || x === "1" || x === true) return 1;
  if (typeof x === "string") {
    x = x.trim();
    if (["감지됨","detected","on","alarm","true","TRUE"].includes(x)) return 1;
    if (["정상","ok","off","false","FALSE","0"].includes(x)) return 0;
  }
  return 0; // 모르면 안전하게 정상(0)
}

const bit = toBit(v);

// 상태 저장하고 다음 노드로 전달
flow.set("shz_status", bit);
return { payload: bit };

// 수신 JSON 문자열 → 파싱
if (typeof msg.payload === "string") {
    msg.payload = JSON.parse(msg.payload);
}

// chart 용 메시지 구성
return { payload: msg.payload.value };

let value = msg.payload.value;
const threshold = 65;

msg.value = value;

