// 보관 개수
const N = 20;

// payload 파싱
let p = msg.payload;
if (typeof p === "string") {
  try { p = JSON.parse(p); } catch(e) { p = {}; }
}

const sensorId = p.sensor_id || msg.topic || "unknown";

// 상태 텍스트 산정
let statusText = p.status;
if (!statusText) {
  const ev = (p.event || "").toLowerCase();
  statusText = (ev.includes("detected") || ev.includes("fire") || ev.includes("smoke")) ? "감지" : "정상";
}
const isAlert = (statusText !== "정상");
const value = (p.value !== undefined) ? p.value : null;

// 타임스탬프 문자열
function tsStr(t){
  const d = new Date(t);
  const z = n => (n<10?"0":"")+n;
  return `${d.getFullYear()}-${z(d.getMonth()+1)}-${z(d.getDate())} ${z(d.getHours())}:${z(d.getMinutes())}:${z(d.getSeconds())}`;
}
const ts = Date.now();

// 히스토리 적재 (flow context)
let hist = flow.get("sensor_hist") || {};
let arr = hist[sensorId] || [];
arr.push({ ts, tsStr: tsStr(ts), sensor: sensorId, status: statusText, alert: isAlert, value });
if (arr.length > N) arr = arr.slice(-N);
hist[sensorId] = arr;
flow.set("sensor_hist", hist);

// 다음 단계에서 합치기 위해 전달
msg.hist = hist;
return msg;

// 히스토리 테이블 구성 (상태만 색 강조)
const hist = flow.get("sensor_hist") || {};

// 모든 센서 히스토리를 합치고 최신순 정렬
let rows = [];
for (const k in hist) rows = rows.concat(hist[k]);
rows.sort((a, b) => b.ts - a.ts);

// 상태 컬럼만 HTML 색상 적용
const colored = rows.map(r => {
  const statusText = r.status || (r.alert ? "감지" : "정상");
  const statusHTML = r.alert
    ? "<span style='color:#c62828; font-weight:600;'>"+statusText+"</span>" // 빨강 굵게
    : "<span style='color:#2e7d32;'>"+statusText+"</span>";                 // 초록

  return {
    tsStr: r.tsStr,                 // 시간 (예: 2025-08-13 19:23:45)
    sensor: r.sensor,               // 센서 ID
    status: statusHTML,             // ← 색 강조된 상태
    value: (r.value ?? "")          // 값(없으면 빈칸)
  };
});

// ui_table에 투입
msg.payload = colored;
return msg;

